import{_ as d,o as e,c as o,a2 as a}from"./chunks/framework.DvFsUg-r.js";const T=JSON.parse('{"title":"플랫폼 관리 기능 이관 — API Contracts (Phase 1)","description":"","frontmatter":{"title":"플랫폼 관리 기능 이관 — API Contracts (Phase 1)","feature_id":"004","created":"2026-05-30 22:30 (KST)","date":"2026-05-30T00:00:00.000Z"},"headers":[],"relativePath":"specs/004-platform-admin-migration/contracts/rest-api.md","filePath":"specs/004-platform-admin-migration/contracts/rest-api.md","lastUpdated":null}'),c={name:"specs/004-platform-admin-migration/contracts/rest-api.md"};function r(i,t,s,h,l,p){return e(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="api-contracts-플랫폼-관리-기능-이관" tabindex="-1">API Contracts: 플랫폼 관리 기능 이관 <a class="header-anchor" href="#api-contracts-플랫폼-관리-기능-이관" aria-label="Permalink to &quot;API Contracts: 플랫폼 관리 기능 이관&quot;">​</a></h1><p>소스 컨트롤러 매핑을 그대로 이관(적응). 모든 응답은 <code>ApiResponse&lt;T&gt;</code> (<code>success, code, message, data</code>). 목록은 <code>PageResponse&lt;T&gt;</code>. <code>/api/v1/auth/**</code> 와 actuator 외 모든 엔드포인트는 <strong>JWT 인증 + 메뉴/역할 권한</strong> 필요.</p><blockquote><p>공통 목록 파라미터: <code>keyword</code>, <code>page</code>(기본 0), <code>size</code>(기본 20), 기능별 필터.</p></blockquote><h2 id="인증-—-api-v1-auth" tabindex="-1">인증 — <code>/api/v1/auth</code> <a class="header-anchor" href="#인증-—-api-v1-auth" aria-label="Permalink to &quot;인증 — `/api/v1/auth`&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>설명</th></tr></thead><tbody><tr><td>POST</td><td><code>/login</code></td><td>자격증명 검증 → Access/Refresh 토큰. 성공/실패 <code>SYS_LOGIN_HISTORY</code> 기록</td></tr><tr><td>POST</td><td><code>/refresh</code></td><td>Refresh 토큰으로 Access 갱신</td></tr><tr><td>GET</td><td><code>/me</code></td><td>현재 사용자 + 권한/메뉴</td></tr><tr><td>POST</td><td><code>/logout</code></td><td>토큰 무효화</td></tr></tbody></table><h2 id="사용자-—-api-v1-users" tabindex="-1">사용자 — <code>/api/v1/users</code> <a class="header-anchor" href="#사용자-—-api-v1-users" aria-label="Permalink to &quot;사용자 — `/api/v1/users`&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>설명</th></tr></thead><tbody><tr><td>GET</td><td>``</td><td>목록(페이징)</td></tr><tr><td>GET</td><td><code>/{id}</code></td><td>단건</td></tr><tr><td>POST</td><td>``</td><td>생성</td></tr><tr><td>PUT</td><td><code>/{id}</code></td><td>수정(관리자 <strong>비밀번호 초기화</strong> 포함)</td></tr><tr><td>DELETE</td><td><code>/{id}</code></td><td>비활성화/삭제</td></tr><tr><td>PUT</td><td><code>/profile</code></td><td>내 프로필 수정</td></tr><tr><td>PUT</td><td><code>/password</code></td><td>본인 비밀번호 변경</td></tr><tr><td>PUT</td><td><code>/{id}/roles</code></td><td>역할 배정</td></tr></tbody></table><h2 id="역할-—-api-v1-roles" tabindex="-1">역할 — <code>/api/v1/roles</code> <a class="header-anchor" href="#역할-—-api-v1-roles" aria-label="Permalink to &quot;역할 — `/api/v1/roles`&quot;">​</a></h2><p>표준 CRUD: 목록 <code>GET</code>, 단건 <code>GET /{id}</code>, 생성 <code>POST</code>, 수정 <code>PUT /{id}</code>, 삭제 <code>DELETE /{id}</code> (+ 역할-권한 매핑).</p><h2 id="메뉴·메뉴권한-—-api-v1-menus" tabindex="-1">메뉴·메뉴권한 — <code>/api/v1/menus</code> <a class="header-anchor" href="#메뉴·메뉴권한-—-api-v1-menus" aria-label="Permalink to &quot;메뉴·메뉴권한 — `/api/v1/menus`&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>설명</th></tr></thead><tbody><tr><td>GET</td><td><code>/my</code></td><td>내 접근가능 메뉴 트리</td></tr><tr><td>GET</td><td><code>/{id}</code></td><td>단건</td></tr><tr><td>POST</td><td>``</td><td>생성</td></tr><tr><td>PUT</td><td><code>/{id}</code></td><td>수정</td></tr><tr><td>DELETE</td><td><code>/{id}</code></td><td>삭제</td></tr><tr><td>PUT</td><td><code>/reorder</code></td><td>정렬 변경</td></tr><tr><td>POST</td><td><code>/{id}/access</code></td><td>메뉴 접근 기록(<code>AUDIT_MENU_ACCESS</code>)</td></tr><tr><td>GET</td><td><code>/roles/{roleId}/permissions</code></td><td>역할별 메뉴 권한 조회</td></tr><tr><td>PUT</td><td><code>/roles/{roleId}/permissions</code></td><td>역할별 메뉴 권한 설정</td></tr><tr><td>GET/POST/DELETE</td><td><code>/favorites[/{menuId}]</code></td><td>즐겨찾기</td></tr></tbody></table><h2 id="부서-—-api-v1-depts" tabindex="-1">부서 — <code>/api/v1/depts</code> <a class="header-anchor" href="#부서-—-api-v1-depts" aria-label="Permalink to &quot;부서 — `/api/v1/depts`&quot;">​</a></h2><p>표준 CRUD: 목록 <code>GET</code>, 단건 <code>GET /{id}</code>, 생성 <code>POST</code>, 수정 <code>PUT /{id}</code>, 삭제 <code>DELETE /{id}</code> (계층).</p><h2 id="공통코드-—-api-v1-codes" tabindex="-1">공통코드 — <code>/api/v1/codes</code> <a class="header-anchor" href="#공통코드-—-api-v1-codes" aria-label="Permalink to &quot;공통코드 — `/api/v1/codes`&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>설명</th></tr></thead><tbody><tr><td>GET</td><td><code>/groups</code></td><td>그룹 목록</td></tr><tr><td>GET</td><td><code>/groups/{groupCode}</code></td><td>그룹 단건</td></tr><tr><td>POST/PUT/DELETE</td><td><code>/groups[/{groupCode}]</code></td><td>그룹 CRUD</td></tr><tr><td>GET</td><td><code>/groups/{groupCode}/details</code></td><td>코드 항목 목록</td></tr><tr><td>POST</td><td><code>/groups/{groupCode}/details</code></td><td>항목 생성</td></tr><tr><td>PUT/DELETE</td><td><code>/groups/{groupCode}/details/{codeValue}</code></td><td>항목 수정/삭제</td></tr></tbody></table><h2 id="다국어-—-api-v1-messages" tabindex="-1">다국어 — <code>/api/v1/messages</code> <a class="header-anchor" href="#다국어-—-api-v1-messages" aria-label="Permalink to &quot;다국어 — `/api/v1/messages`&quot;">​</a></h2><p>목록 <code>GET</code>, 언어별 일괄 <code>GET /bulk/{langCode}</code>, 생성 <code>POST</code>, 수정 <code>PUT /{id}</code>, 삭제 <code>DELETE /{id}</code>.</p><h2 id="시스템-설정-—-api-v1-settings" tabindex="-1">시스템 설정 — <code>/api/v1/settings</code> <a class="header-anchor" href="#시스템-설정-—-api-v1-settings" aria-label="Permalink to &quot;시스템 설정 — `/api/v1/settings`&quot;">​</a></h2><p>목록 <code>GET</code>, 단건 <code>GET /{key}</code>, 수정 <code>PUT /{key}</code>, 삭제 <code>DELETE /{key}</code>.</p><h2 id="메일-—-api-v1-mails" tabindex="-1">메일 — <code>/api/v1/mails</code> <a class="header-anchor" href="#메일-—-api-v1-mails" aria-label="Permalink to &quot;메일 — `/api/v1/mails`&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>설명</th></tr></thead><tbody><tr><td>GET/POST</td><td><code>/templates</code></td><td>양식 목록/생성</td></tr><tr><td>GET/PUT/DELETE</td><td><code>/templates/{id}</code></td><td>양식 단건/수정/삭제</td></tr><tr><td>POST</td><td><code>/send</code></td><td>발송(양식+변수) → <code>SYS_MAIL_LOG</code></td></tr><tr><td>GET</td><td><code>/logs</code></td><td>발송 현황 목록</td></tr><tr><td>GET</td><td><code>/logs/{id}</code></td><td>발송 단건</td></tr><tr><td>POST</td><td><code>/logs/{id}/resend</code></td><td>재발송</td></tr></tbody></table><h2 id="결재-—-api-v1-approvals-다단계" tabindex="-1">결재 — <code>/api/v1/approvals</code> (다단계) <a class="header-anchor" href="#결재-—-api-v1-approvals-다단계" aria-label="Permalink to &quot;결재 — `/api/v1/approvals` (다단계)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>설명</th></tr></thead><tbody><tr><td>GET/POST</td><td><code>/templates</code></td><td>결재 양식 목록/생성</td></tr><tr><td>GET/PUT/DELETE</td><td><code>/templates/{id}</code></td><td>양식 단건/수정/삭제</td></tr><tr><td>GET/POST</td><td><code>/templates/{templateId}/lines</code></td><td>결재선 조회/추가</td></tr><tr><td>DELETE</td><td><code>/templates/{templateId}/lines/{lineId}</code></td><td>결재선 삭제</td></tr><tr><td>POST</td><td>``</td><td>상신(문서 생성)</td></tr><tr><td>GET</td><td><code>/{id}</code></td><td>문서 단건(단계 포함)</td></tr><tr><td>POST</td><td><code>/{id}/action</code></td><td>승인/반려(현재 단계) → 다음 단계 진행 or 종료</td></tr><tr><td>GET</td><td><code>/pending</code></td><td>내 처리대기 목록</td></tr><tr><td>GET</td><td><code>/monitor</code></td><td>진행 현황(모니터링)</td></tr><tr><td>GET</td><td><code>/overdue</code></td><td>지연 결재</td></tr><tr><td>GET</td><td><code>/stats</code></td><td>결재 통계</td></tr><tr><td>POST</td><td><code>/{id}/force</code></td><td>관리자 강제처리</td></tr></tbody></table><h2 id="권한-신청-—-api-v1-permissions" tabindex="-1">권한 신청 — <code>/api/v1/permissions</code> <a class="header-anchor" href="#권한-신청-—-api-v1-permissions" aria-label="Permalink to &quot;권한 신청 — `/api/v1/permissions`&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>설명</th></tr></thead><tbody><tr><td>GET</td><td><code>/my</code></td><td>내 신청 목록</td></tr><tr><td>GET</td><td><code>/{id}</code></td><td>단건</td></tr><tr><td>POST</td><td>``</td><td>권한 신청(→ 결재 연동)</td></tr><tr><td>POST</td><td><code>/{id}/action</code></td><td>승인/반려 → 승인 시 역할/메뉴 권한 반영</td></tr></tbody></table><h2 id="파일-—-api-v1-files" tabindex="-1">파일 — <code>/api/v1/files</code> <a class="header-anchor" href="#파일-—-api-v1-files" aria-label="Permalink to &quot;파일 — `/api/v1/files`&quot;">​</a></h2><p><code>POST /upload</code>(→<code>AUDIT_FILE_LOG</code>) / <code>GET /{id}/download</code> / <code>DELETE /{id}</code>.</p><h2 id="감사-이력-조회-—-api-v1-audit" tabindex="-1">감사 이력(조회) — <code>/api/v1/audit</code> <a class="header-anchor" href="#감사-이력-조회-—-api-v1-audit" aria-label="Permalink to &quot;감사 이력(조회) — `/api/v1/audit`&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>이력</th></tr></thead><tbody><tr><td>GET</td><td><code>/login-history</code></td><td>로그인 이력</td></tr><tr><td>GET</td><td><code>/rest-logs</code></td><td>REST API 이력</td></tr><tr><td>GET</td><td><code>/sql-logs</code></td><td>SQL 실행 이력</td></tr><tr><td>GET</td><td><code>/exception-logs</code></td><td>예외 이력</td></tr><tr><td>GET</td><td><code>/data-changes</code></td><td>데이터 변경 이력</td></tr><tr><td>GET</td><td><code>/file-logs</code></td><td>파일 이력</td></tr><tr><td>GET</td><td><code>/menu-access</code></td><td>메뉴 접근 이력</td></tr></tbody></table><blockquote><p>공통 필터: <code>from</code>, <code>to</code>(기간), <code>actor</code>/<code>userId</code>, <code>keyword</code>. 1년 이내만 조회 대상.</p></blockquote><h2 id="권한·오류-규약" tabindex="-1">권한·오류 규약 <a class="header-anchor" href="#권한·오류-규약" aria-label="Permalink to &quot;권한·오류 규약&quot;">​</a></h2><ul><li>미인증: <code>401</code>. 권한 없음: <code>403</code>(FR-2/SC-2, 우회 0건).</li><li>검증 실패: <code>400</code> + <code>ApiResponse.code</code> 오류코드. 미존재: <code>404</code>.</li><li>서버 예외: <code>500</code> + <code>AUDIT_EXCEPTION_LOG</code> 기록.</li></ul>',32)])])}const E=d(c,[["render",r]]);export{T as __pageData,E as default};
